   211	fn write_config_atomically(path: &Path, contents: &str) -> anyhow::Result<()> {
   212	    let parent = path
   213	        .parent()
   214	        .context("Scope config path is missing a parent directory")?;
   215	    let temp_path = temporary_config_path(parent)?;
   216	    let result = (|| -> anyhow::Result<()> {
   217	        let mut file = OpenOptions::new()
   218	            .write(true)
   219	            .create_new(true)
   220	            .open(&temp_path)
   221	            .context("create temporary .scope/repo.json")?;
   222	        file.write_all(contents.as_bytes())
   223	            .context("write temporary .scope/repo.json")?;
   224	        file.sync_all().context("sync temporary .scope/repo.json")?;
   225	        drop(file);
   226	        fs::rename(&temp_path, path).context("replace .scope/repo.json")?;
   227	        Ok(())
   228	    })();
   229	
   230	    if result.is_err() {
   231	        let _ = fs::remove_file(&temp_path);
   232	    }
   233	
   234	    result
   235	}
