   278	fn append_missing_ignore_patterns(path: &Path, existing: &str, action: &str) -> anyhow::Result<()> {
   279	    let missing = LOCAL_ONLY_SCOPE_IGNORE_PATTERNS
   280	        .iter()
   281	        .copied()
   282	        .filter(|path| !existing.lines().map(str::trim).any(|line| line == *path))
   283	        .collect::<Vec<_>>();
   284	    if missing.is_empty() {
   285	        return Ok(());
   286	    }
   287	
   288	    let mut file = OpenOptions::new()
   289	        .append(true)
   290	        .create(true)
   291	        .open(path)
   292	        .with_context(|| format!("open {}", path.display()))?;
   293	    if !existing.is_empty() && !existing.ends_with('\n') {
   294	        file.write_all(b"\n").context(action.to_string())?;
   295	    }
   296	    for pattern in missing {
   297	        file.write_all(format!("{pattern}\n").as_bytes())
   298	            .context(action.to_string())?;
   299	    }
   300	    Ok(())
   301	}
