     8	pub fn settlement_for(
     9	    stake_credits: u32,
    10	    disposition: RequestDisposition,
    11	    settled_at_unix: u64,
    12	) -> RequestSettlement {
    13	    // `Accepted` is reserved for the merge flow; direct maintainer resolution
    14	    // rejects it before settlement so acceptance cannot pay without a clean merge.
    15	    let (refunded_credits, reward_credits) = match disposition {
    16	        RequestDisposition::Accepted => (stake_credits, maximum_request_reward(stake_credits)),
    17	        RequestDisposition::UsefulNotMerged => (stake_credits, stake_credits / 5),
    18	        RequestDisposition::HiddenContext | RequestDisposition::NotAligned => (stake_credits, 0),
    19	        RequestDisposition::Duplicate => (stake_credits / 2, 0),
    20	        RequestDisposition::Abandoned | RequestDisposition::LowQuality => (0, 0),
    21	    };
    22	    RequestSettlement {
    23	        disposition,
    24	        stake_credits,
    25	        refunded_credits,
    26	        reward_credits,
    27	        burned_credits: stake_credits.saturating_sub(refunded_credits),
    28	        settled_at_unix,
    29	    }
    30	}
    31	
    32	pub(super) fn maximum_request_reward(stake_credits: u32) -> u32 {
    33	    stake_credits / 2
    34	}
